using System.ComponentModel;
using System.Text.Json;
using ModelContextProtocol.Server;

[McpServerToolType]
public static class ConfigTools
{
    [McpServerTool, Description("Looks up a configuration value by key name.")]
    public static string GetConfigValue(
        [Description("The configuration key to look up (e.g. 'MaxRetries', 'Timeout')")] string key)
    {
        var config = AppConfiguration.Current;
        return config.TryGetValue(key, out var value)
            ? $"{key} = {value}"
            : $"Key '{key}' not found. Available keys: {string.Join(", ", config.Keys)}";
    }

    [McpServerTool, Description("Lists all available configuration keys.")]
    public static string ListConfigKeys()
    {
        return string.Join("\n", AppConfiguration.Current.Keys.Order());
    }

    [McpServerTool, Description("Updates a configuration value. Returns the old and new values.")]
    public static string SetConfigValue(
        [Description("The configuration key to set")] string key,
        [Description("The new value for the key")] string value)
    {
        var config = AppConfiguration.Current;
        var hadOld = config.TryGetValue(key, out var oldValue);
        config[key] = value;

        return hadOld
            ? $"Updated '{key}': '{oldValue}' -> '{value}'"
            : $"Created '{key}' = '{value}'";
    }
}

using System.ComponentModel;
using System.Text.Json;
using ModelContextProtocol.Server;

[McpServerResourceType]
public static class ConfigResources
{
    private static readonly JsonSerializerOptions JsonOptions = new() { WriteIndented = true };

    [McpServerResource(UriTemplate = "config://app/all", Name = "Full App Configuration",
        MimeType = "application/json"),
     Description("Returns the complete application configuration as JSON.")]
    public static string GetAllConfig() =>
        JsonSerializer.Serialize(AppConfiguration.Current, JsonOptions);

    [McpServerResource(UriTemplate = "config://app/summary", Name = "Config Summary",
        MimeType = "text/plain"),
     Description("Returns a human-readable summary of the configuration.")]
    public static string GetConfigSummary() =>
        $"Application Configuration ({AppConfiguration.Current.Count} keys)\n" +
        string.Join("\n", AppConfiguration.Current
            .OrderBy(kv => kv.Key)
            .Select(kv => $"  {kv.Key}: {kv.Value}"));
}

using System.Collections.Concurrent;

/// <summary>
/// Thread-safe in-memory configuration store shared across tools and resources.
/// </summary>
public static class AppConfiguration
{
    public static ConcurrentDictionary<string, string> Current { get; } = new(
        new Dictionary<string, string>
        {
            ["AppName"] = "ConfigMcpServer",
            ["Environment"] = "Development",
            ["MaxRetries"] = "3",
            ["Timeout"] = "30s",
            ["LogLevel"] = "Information",
            ["FeatureFlags.DarkMode"] = "true",
            ["FeatureFlags.BetaAccess"] = "false"
        });
}

