builder.Services.AddMcpServer(options =>
{
    options.ServerInfo = new() { Name = "ConfigMcpServer", Version = "1.0.0" };
    options.ServerInstructions = "An MCP server that manages application configuration. "
        + "Use tools to read/write config values, or read resources for a full config snapshot.";
})
.WithHttpTransport()
.WithToolsFromAssembly()
.WithResourcesFromAssembly();

var app = builder.Build();

app.MapMcp();
app.MapGet("/health", () => "ok");

app.Run();

